      function CF_AMOUNTFormula return char is
begin
  IF :CALCULATION_FLG NOT IN ('1','6','11') OR :CALCULATION_FLG IS  NULL THEN
  	 RETURN LTRIM((TO_CHAR(:AMOUNT,'9999990D99')));
  ELSE
  	 RETURN :AMOUNT;
  END IF;
end;

function CF_IND_PRODUCTFormula return Char is
V_IND_PRODUCT_CODE PEN_PRODUCTS.PRODUCT_CODE%TYPE;
CURSOR cur_ind_account IS SELECT D.PRODUCT_CODE FROM PEN_ACCOUNT A, PEN_ACCOUNT B, PEN_QC_PER_PRODINST C, PEN_PRODUCT_PER_INSTITUTIONS D WHERE A.INS_INSURED_ID = B.INS_INSURED_ID AND B.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR --SYSTEM DEAD_ACCOUNT_NO AND A.TEMP_FLG = '0' AND A.USAGE_FLG = '1' AND NVL(A.CONVERTED_FLG,'0') != '1' AND A.QCPRODINS_QC_PER_PRODINST_CODE = C.QC_PER_PRODINST_CODE AND C.PRODUCT_PER_INSTITUTION_CODE = D.PRODUCT_PER_INSTITUTION_CODE AND D.PRODUCT_CODE IN ('00001', '00002') AND D.INSTITUTION_CODE = (SELECT H.INSTITUTION_CODE FROM PEN_ACCOUNT F, PEN_QC_PER_PRODINST G, PEN_PRODUCT_PER_INSTITUTIONS H WHERE F.QCPRODINS_QC_PER_PRODINST_CODE = G.QC_PER_PRODINST_CODE AND G.PRODUCT_PER_INSTITUTION_CODE = H.PRODUCT_PER_INSTITUTION_CODE AND F.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR);
begin OPEN cur_ind_account; FETCH cur_ind_account INTO V_IND_PRODUCT_CODE; CLOSE cur_ind_account;
RETURN V_IND_PRODUCT_CODE;
end;

