OM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '01069' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id_IND ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE UNION SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME ---EE/DS FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '99111' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '99247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id_IND ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE ORDER BY 1;
BEGIN
--IF NVL(:P_IS_MULTI_PENSIONER ,0)=0 THEN /* V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1', 0,0,'00001','00172','00247'); IF V_BRANCH_CODE IS NULL THEN V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1', 0,0,'00001','00069','00247'); END IF;
-- CHRYS 9/8/2017 IF V_BRANCH_CODE IS NULL THEN V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1', 0,0,'00001','01069','00247'); END IF; -- END CHRYS 9/8/2017
IF V_BRANCH_CODE IS NOT NULL THEN SELECT A.BRANCH_NAME INTO V_BRANCH_NAME FROM COM_ORG_BRANCHES A WHERE A.BRANCH_CODE = V_BRANCH_CODE; ELSE V_BRANCH_NAME := ' '; END IF;*/ /* ELSE --- AN EXEI POLLAPLES SYNTAXEIS NA FAINONTAI OLA TA BRANCHES STHN KOINOPOIHSH L_AA := 2; FOR X IN C_MULTI_BRANCHES LOOP IF X.foreas IS NOT NULL THEN -- L_FOREAS := to_char(L_AA)||'.'||L_FOREAS||' '||X.foreas||CHR(10); L_FOREAS := L_FOREAS||' '||X.foreas||CHR(10); L_AA := L_AA+1; END IF; END LOOP; V_BRANCH_NAME := L_FOREAS; END IF; */
OPEN C1; FETCH C1 INTO V_BRANCH_CODE, V_BRANCH_NAME ; CLOSE C1;
RETURN NVL(V_BRANCH_NAME, ' '); EXCEPTION WHEN OTHERS THEN RETURN NULL;
END;

      FUNCTION CF_PRESUMED_WAGEFormula RETURN NUMBER IS

v_amount NUMBER;

CURSOR cur_presumed IS 
SELECT A.PRESUMED_WAGES
FROM COM_CURRENT_PRESUMED_WAGES A
WHERE A.PREWAG_INSURANCE_CLASS = :INSURANCE_CLASS
AND A.FROM_DAILY_WAGES <= ROUND(:NOTICE_TOTAL_SALARY/:NOTICE_TOTAL_DAYS,2)
AND (A.TO_DAILY_WAGES >= ROUND(:NOTICE_TOTAL_SALARY/:NOTICE_TOTAL_DAYS,2)
     OR :INSURANCE_CLASS = 28)
AND A.EFFECTIVENESS_START_DATE <= TO_DATE('31'||'12'||:PERIOD_YEAR_TO,'DD/MM/RRRR') 
ORDER BY A.EFFECTIVENESS_START_DATE DESC;

BEGIN
 

 IF  :PERIOD_YEAR_TO IS NOT NULL THEN
  IF NVL(:NOTICE_TOTAL_DAYS,0)!= 0 THEN 
	  OPEN cur_presumed;
	  FETCH cur_presumed
	  INTO v_amount;
	  CLOSE cur_presumed;
  ELSE 
  	v_amount:=NULL;
  END IF;
END IF;
  RETURN v_amount;
END;

