      FUNCTION CF_PROCCESS_IDFormula RETURN NUMBER IS

V_PROCESS_ID NUMBER;

CURSOR CUR_PROCESS IS
SELECT A.PROCESS_ID
FROM PEN_SUMMARIZATION_PER_INSURED A
WHERE A.INSURED_ID = :P_INSURED_ID
ORDER BY A.PROCESS_ID DESC;

BEGIN
	
	OPEN CUR_PROCESS;
	FETCH CUR_PROCESS
	INTO V_PROCESS_ID;
	CLOSE CUR_PROCESS;
	
  :P_PROCESS_ID:=V_PROCESS_ID;
  RETURN :P_PROCESS_ID;
END;

      

FUNCTION CF_YEARS_USEDFormula RETURN CHAR IS

TYPE T_YEARS_USED IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
YEARS T_YEARS_USED ;
I NUMBER:=1;
LINE VARCHAR2(200) :=''; --CONTAINTS YEARS WITH FORM 1999,2000,2001

CURSOR CUR_YEARS_USED IS
SELECT A.YEAR_USED
FROM PEN_SUMMAR_CLASS_YEARS A 
WHERE A.PROCESS_ID = :P_PROCESS_ID;

BEGIN
  
  OPEN CUR_YEARS_USED;

   LOOP
	  FETCH CUR_YEARS_USED
	  INTO YEARS(I);
	  I:= I+1;
	  EXIT WHEN CUR_YEARS_USED%NOTFOUND;  
   END LOOP;

  FOR K IN 1..YEARS.COUNT LOOP
  IF k!=years.COUNT THEN 
     LINE := LINE || TO_CHAR(YEARS(K)) || ',';     
  ELSE
    LINE := LINE || TO_CHAR(YEARS(K));     
  END IF;
  END LOOP;
  
  CLOSE CUR_YEARS_USED;
  
  RETURN LINE;
  
END;

      function CF_TERMINATION_TRI_YEARSForm return Date is

V_RESULT DATE;

CURSOR cur_DATE IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00315' AND
	     A.Dec_Fact_Type_Code = '00059';

begin

  IF :DATE_OF_DEATH IS NOT NULL THEN 
  	RETURN LAST_DAY(ADD_MONTHS(:DATE_OF_DEATH,36))+1;
  ELSE
		  OPEN cur_DATE;
		  FETCH cur_DATE
		  INTO V_RESULT;
		  CLOSE cur_DATE;

      RETURN LAST_DAY(ADD_MONTHS(V_RESULT,36))+1;  

  END IF;
  
END;

