      function CF_EXIST_TEMPFormula return Number is
  cursor Find_temp_pension is
   select count(*)
		from pen_temp_decision_instance a
        where a.ins_insured_id= :P_INSURED_ID
          and a.status='1'
          and a.qc_per_prodinst_code=decode(:product_CODE, '00001','1','00002','9','3');
          
cursor Find_temp_pension_debt is
   select count(*)
		from pen_temp_decision_instance a
        where a.ins_insured_id= :P_INSURED_ID
          and a.status='1'
          and exists (  select '1' 
                        from PEN_TEMP_DEC_INSTANCE_DEBTS b
											WHERE b.STATUS='1'
											  AND DT_DEC_UNIT_CODE= a.DT_DEC_UNIT_CODE
											  AND  DT_DECISION_YEAR= a.DT_DECISION_YEAR
											  AND  DEC_INCR_SEQ_NO = a.DEC_INCR_SEQ_NO
											)               
          and a.qc_per_prodinst_code=decode(:product_CODE, '00001','1','00002','9','3');
           
v_temp_cnt number          ;
v_temp_debts_exist number;
v_desrc varchar2(1000);


begin
  
  if :INSTITUTION_CODE='1' then
		 	open Find_temp_pension;
		 	fetch Find_temp_pension into v_temp_cnt;
		 	close Find_temp_pension;		
			 if v_temp_cnt>0 then
			 	v_desrc:='Συμψηφίζονται ποσά Προσωρινής Σύνταξης';
			 	open Find_temp_pension_debt;
			 	fetch Find_temp_pension_debt into v_temp_debts_exist;
			 	close Find_temp_pension_debt;
			 	if v_temp_debts_exist>0 then
			 		v_desrc:=v_desrc||' και τυχόν υπόλοιπα οφειλών, θα παρακρατούνται από την παρούσα απόφαση'||'.';
			 	else
			 		v_desrc:=v_desrc||'.';
			 	end if;	
			 	:CP_EXIST_TEMP:=v_desrc;
			 END IF;		
  end if;
  
  RETURN 0;
end;

