      function CF_get_days_for_othersFormula return Char is

L_TOTAL       VARCHAR2 (500);
lidaysofmonth NUMBER := 25;

CURSOR C_1 IS
select SUBSTR(:yy_mm_dd_asf_ergasias,1,2) YY,
       SUBSTR(:yy_mm_dd_asf_ergasias,3,2) MM,
       SUBSTR(:yy_mm_dd_asf_ergasias,5,2) DD
  from dual
;

begin
  :CP_YY_MULTI  := 0;
  :CP_MM_MULTI	:= 0;
  :CP_DD_MULTI  := 0; 
  
 IF :ESEPS_CODE = 21000 THEN
  
  OPEN C_1;
   FETCH C_1 INTO :CP_YY_MULTI, :CP_MM_MULTI, :CP_DD_MULTI;
  CLOSE C_1;
  	
 ELSE
   -- Call the procedure
  com_util_days.convdaysinyearsmontsdays(pisumofdays   => :CALCULATED_DAYS,
                                         pidaysofmonth => lidaysofmonth,
                                         poyears       => :CP_YY_MULTI,
                                         pomonths      => :CP_MM_MULTI,
                                         podays        => :CP_DD_MULTI);
 
 
 --srw.message(100, ':CALCULATED_DAYS : ' ||:CALCULATED_DAYS );
 --srw.message(100, ':CP_YY_MULTI : ' ||:CP_YY_MULTI ) ;
 --srw.message(100, ':CP_MM_MULTI : ' ||:CP_MM_MULTI ) ;
 --srw.message(100, ':CP_DD_MULTI : ' ||:CP_DD_MULTI )  ;
  :CP_YY_MULTI := ROUND(:CP_YY_MULTI);
  :CP_MM_MULTI := ROUND(:CP_MM_MULTI);
  :CP_DD_MULTI := ROUND(:CP_DD_MULTI);
                          
  if round(:CP_DD_MULTI) = 25
  	then :CP_MM_MULTI := :CP_MM_MULTI+1;
  	     :CP_DD_MULTI 	:= 0;
  end if;  
  
 END IF; 
 
 --srw.message(100, 'round(:CP_DD_MULTI) ' ||round(:CP_DD_MULTI));
 --srw.message(100, 'L_TOTAL ' || L_TOTAL);
 
 L_TOTAL := :CP_YY_MULTI||' '||'ΕΤΗ'||CHR(10)||:CP_MM_MULTI||' '||'ΜΗΝΕΣ'||CHR(10)||:CP_DD_MULTI||' '||'ΗΜΕΡΕΣ';
 --  srw.message(100, 'L_TOTAL ' || L_TOTAL);
 	
 return (L_TOTAL);
 
end;

