end;

      function F_13FormatTrigger return boolean is
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;

begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019
  V_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019
  INTO V_2019;
	CLOSE CUR_2019;
	  
  IF V_2019 = '1' THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;

  return (TRUE);
end;

