  IF :CP_PROD_PER_INSTITUTION_CODE IN (1372,1257,1357,1366,1361,1367,1371,1369,1370)
  	 THEN return 'Επιφυλασσόμαστε για τυχόν τροποποίηση της παρούσας απόφασης ως προς το καταβαλλόμενο ποσό της σύνταξης μετά την ολοκλήρωση της διαδικασίας του Επανυπολογισμού'||CHR(10);
     ELSE return null;
  END IF;	
  EXCEPTION WHEN OTHERS THEN RETURN NULL;
end;

