      function CF_EMKBFFormula return Number is
CURSOR	CUR_EMKBF IS

SELECT 	AMOUNT
FROM 		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE		ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND			CC_PER_BE_TYPE_PER_DECINS_UPD = '1' 
AND		CP_CALCULATION_PARAMETER_CODE = 'EMKBF';

V_AMOUNT			NUMBER;
begin
  OPEN	CUR_EMKBF;
  FETCH	CUR_EMKBF
  INTO V_AMOUNT;
  CLOSE	CUR_EMKBF;
  
  RETURN V_AMOUNT;
end;

